#include "as7341.h"
static Adafruit_AS7341 as;
static uint16_t _ch[12]={0};
static unsigned long _last=0;
void as7341_setup(){
  Wire.begin();
  if(!as.begin()){Serial.println("[as7341] Init failed!");return;}
  as.setATIME(100);as.setASTEP(999);as.setGain(AS7341_GAIN_256X);
  Serial.println("[as7341] OK");
}
void as7341_loop(){
  if(millis()-_last<1000)return;
  _last=millis();
  if(as.readAllChannels()){for(int i=0;i<12;i++)_ch[i]=as.getChannel((as7341_color_channel_t)i);}
}
uint16_t as7341_get_channel(uint8_t ch){return ch<12?_ch[ch]:0;}
